import React, { useEffect, useMemo, useState } from "react";
import { incidentsService } from "../api/incidentsService";

const severityOrder = { critical: 4, high: 3, medium: 2, low: 1 };
const validStates = ["open", "triaged", "assigned", "in_progress", "resolved", "closed"];

function IncidentCommandCenter() {
  const [incidents, setIncidents] = useState([]);
  const [dispatchQueue, setDispatchQueue] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [newIncident, setNewIncident] = useState({
    incident_type: "overflow_risk",
    severity: "medium",
    bin_id: "",
    description: "",
  });
  const [assignments, setAssignments] = useState({});

  const loadData = async () => {
    setLoading(true);
    setError("");
    try {
      const [allIncidents, queue] = await Promise.all([
        incidentsService.getAll(),
        incidentsService.getDispatchQueue(),
      ]);
      setIncidents(allIncidents);
      setDispatchQueue(queue);
    } catch (_e) {
      setError(
        "Unable to load incidents. If auth is enabled, login and set swms_access_token in localStorage."
      );
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const stats = useMemo(() => {
    const total = incidents.length;
    const active = incidents.filter((i) => !["resolved", "closed"].includes(i.status)).length;
    const critical = incidents.filter((i) => i.severity === "critical").length;
    const resolved = incidents.filter((i) => ["resolved", "closed"].includes(i.status)).length;
    return { total, active, critical, resolved };
  }, [incidents]);

  const sortedIncidents = useMemo(() => {
    return [...incidents].sort((a, b) => {
      const sa = severityOrder[a.severity] || 0;
      const sb = severityOrder[b.severity] || 0;
      if (sa !== sb) return sb - sa;
      return Number(b.id) - Number(a.id);
    });
  }, [incidents]);

  const handleCreateIncident = async (e) => {
    e.preventDefault();
    try {
      await incidentsService.create({
        ...newIncident,
        bin_id: newIncident.bin_id ? Number(newIncident.bin_id) : null,
      });
      setNewIncident({
        incident_type: "overflow_risk",
        severity: "medium",
        bin_id: "",
        description: "",
      });
      await loadData();
    } catch (_e) {
      setError("Failed to create incident.");
    }
  };

  const handleStateChange = async (id, status) => {
    try {
      await incidentsService.updateState(id, status);
      await loadData();
    } catch (_e) {
      setError("Failed to update incident state.");
    }
  };

  const handleAssign = async (id) => {
    const payload = assignments[id] || {};
    try {
      await incidentsService.assign(id, {
        driver_id: payload.driver_id ? Number(payload.driver_id) : null,
        vehicle_id: payload.vehicle_id ? Number(payload.vehicle_id) : null,
        authority_id: payload.authority_id ? Number(payload.authority_id) : null,
      });
      await loadData();
    } catch (_e) {
      setError("Failed to assign incident.");
    }
  };

  return (
    <div className="icc-page">
      <div className="page-header">
        <div className="page-header-icon">🚨</div>
        <h1 className="page-title">Incident Command Center</h1>
        <p className="page-subtitle">Operational control for incident lifecycle and dispatch.</p>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      <section className="icc-stats">
        <div className="icc-stat-card"><p>Total</p><h3>{stats.total}</h3></div>
        <div className="icc-stat-card"><p>Active</p><h3>{stats.active}</h3></div>
        <div className="icc-stat-card"><p>Critical</p><h3>{stats.critical}</h3></div>
        <div className="icc-stat-card"><p>Resolved</p><h3>{stats.resolved}</h3></div>
      </section>

      <section className="icc-layout">
        <article className="icc-panel">
          <h3>Create Incident</h3>
          <form className="icc-form" onSubmit={handleCreateIncident}>
            <input
              value={newIncident.incident_type}
              onChange={(e) => setNewIncident((prev) => ({ ...prev, incident_type: e.target.value }))}
              placeholder="Incident type"
              required
            />
            <select
              value={newIncident.severity}
              onChange={(e) => setNewIncident((prev) => ({ ...prev, severity: e.target.value }))}
            >
              <option value="critical">critical</option>
              <option value="high">high</option>
              <option value="medium">medium</option>
              <option value="low">low</option>
            </select>
            <input
              value={newIncident.bin_id}
              onChange={(e) => setNewIncident((prev) => ({ ...prev, bin_id: e.target.value }))}
              placeholder="Bin ID (optional)"
            />
            <textarea
              value={newIncident.description}
              onChange={(e) => setNewIncident((prev) => ({ ...prev, description: e.target.value }))}
              placeholder="Description"
            />
            <button type="submit" className="btn btn-primary">Create</button>
          </form>
        </article>

        <article className="icc-panel">
          <h3>Dispatch Queue</h3>
          <div className="icc-list">
            {dispatchQueue.map((item) => (
              <div key={item.id} className="icc-list-item">
                <strong>#{item.id}</strong>
                <span>{item.incident_type}</span>
                <span className={`icc-badge ${item.severity}`}>{item.severity}</span>
                <span>{item.status}</span>
              </div>
            ))}
            {!dispatchQueue.length && !loading && <p className="ops-muted">No active dispatch items.</p>}
          </div>
        </article>
      </section>

      <section className="icc-panel">
        <h3>Incident Queue</h3>
        {loading ? (
          <div className="loading-state">Loading incidents...</div>
        ) : (
          <div className="icc-table-wrap">
            <table className="icc-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Type</th>
                  <th>Severity</th>
                  <th>Status</th>
                  <th>State Transition</th>
                  <th>Assign</th>
                </tr>
              </thead>
              <tbody>
                {sortedIncidents.map((incident) => (
                  <tr key={incident.id}>
                    <td>#{incident.id}</td>
                    <td>{incident.incident_type}</td>
                    <td><span className={`icc-badge ${incident.severity}`}>{incident.severity}</span></td>
                    <td>{incident.status}</td>
                    <td>
                      <select
                        value={incident.status}
                        onChange={(e) => handleStateChange(incident.id, e.target.value)}
                      >
                        {validStates.map((s) => (
                          <option key={s} value={s}>{s}</option>
                        ))}
                      </select>
                    </td>
                    <td>
                      <div className="icc-assign-grid">
                        <input
                          placeholder="Driver"
                          value={assignments[incident.id]?.driver_id || ""}
                          onChange={(e) =>
                            setAssignments((prev) => ({
                              ...prev,
                              [incident.id]: { ...prev[incident.id], driver_id: e.target.value },
                            }))
                          }
                        />
                        <input
                          placeholder="Vehicle"
                          value={assignments[incident.id]?.vehicle_id || ""}
                          onChange={(e) =>
                            setAssignments((prev) => ({
                              ...prev,
                              [incident.id]: { ...prev[incident.id], vehicle_id: e.target.value },
                            }))
                          }
                        />
                        <input
                          placeholder="Authority"
                          value={assignments[incident.id]?.authority_id || ""}
                          onChange={(e) =>
                            setAssignments((prev) => ({
                              ...prev,
                              [incident.id]: { ...prev[incident.id], authority_id: e.target.value },
                            }))
                          }
                        />
                        <button type="button" className="btn btn-primary btn-sm" onClick={() => handleAssign(incident.id)}>
                          Assign
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </div>
  );
}

export default IncidentCommandCenter;
